module RefModule(  
    input [4:0] data_in,  
    input write,  
    output reg [4:0] data_out  
);  
  wire [4:0] _tap_data_in = data_in & {5{1'b1}};

    always @(*) begin  
        if (write)  
            data_out = data_in;  
        // else retain previous value (implicit)  
    end  
endmodule
